// Keyed produce: all events for an order are co-located and ordered.
ProducerRecord<String, OrderEvent> record =
    new ProducerRecord<>("orders", order.getId(), event);
producer.send(record);

// Same key -> same partition -> strict offset order:
//   orders-7: [ created@100, paid@101, shipped@102 ]
// A different order may interleave on another partition,
// but the relative order of THIS order's events is guaranteed.

Properties props = new Properties();
props.put("group.id", "fraud-scoring");
props.put("enable.auto.commit", "false"); // commit manually after work
props.put("isolation.level", "read_committed"); // skip aborted txns
props.put("max.poll.records", "500");

try (var consumer = new KafkaConsumer<String, String>(props)) {
    consumer.subscribe(List.of("transactions"));
    while (running) {
        var records = consumer.poll(Duration.ofMillis(200));
        for (var r : records) process(r);          // do the work first
        consumer.commitSync();                       // then commit
    }
}

// Read-process-write done atomically with transactions (EOS).
producer.initTransactions();
while (running) {
    var records = consumer.poll(Duration.ofMillis(200));
    producer.beginTransaction();
    for (var r : records) {
        producer.send(transform(r));            // produce derived events
    }
    // Commit consumer offsets INSIDE the producer transaction:
    producer.sendOffsetsToTransaction(offsetsOf(records),
        consumer.groupMetadata());
    producer.commitTransaction();               // atomic: offsets + output
}

void handle(ConsumerRecord<String, Payment> r) {
    String idemKey = r.value().getPaymentId(); // stable business key
    try (var tx = db.begin()) {
        if (db.exists("SELECT 1 FROM processed WHERE key=?", idemKey)) {
            return; // already done; safe to skip and commit offset
        }
        psp.charge(r.value(), idemKey);           // PSP dedups on idemKey
        db.exec("INSERT INTO processed(key) VALUES(?)", idemKey);
        tx.commit();   // effect + dedup row land together, atomically
    }
}

