// Idempotent consumer: dedup marker + side effect in one DB transaction.
Properties props = new Properties();
props.put(ConsumerConfig.GROUP_ID_CONFIG, "wallet-credits");
props.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, "false");
props.put(ConsumerConfig.MAX_POLL_RECORDS_CONFIG, "200");

try (var consumer = new KafkaConsumer<String, WalletEvent>(props)) {
    consumer.subscribe(List.of("wallet-credits"));
    while (running) {
        var records = consumer.poll(Duration.ofMillis(200));
        for (var r : records) {
            applyOnce(r.value());        // idempotent unit of work
        }
        if (!records.isEmpty()) {
            consumer.commitSync();       // commit ONLY after work is durable
        }
    }
}

void applyOnce(WalletEvent e) {
    String idemKey = e.getEventId();     // stable business id, not offset
    try (Connection c = pool.get()) {
        c.setAutoCommit(false);
        try {
            // INSERT first: unique constraint is the dedup gate.
            try (var ins = c.prepareStatement(
                "INSERT INTO processed_events(event_id) VALUES (?)")) {
                ins.setString(1, idemKey);
                ins.executeUpdate();
            }
            // Side effect lives in the SAME transaction as the marker.
            try (var upd = c.prepareStatement(
                "UPDATE wallets SET balance = balance + ? WHERE id = ?")) {
                upd.setLong(1, e.getAmount());
                upd.setString(2, e.getWalletId());
                upd.executeUpdate();
            }
            c.commit();                  // atomic: marker + effect together
        } catch (SQLException dup) {
            c.rollback();
            if (isUniqueViolation(dup)) {
                return;                  // already processed -> safe no-op
            }
            throw new RuntimeException(dup); // real error: do NOT commit offset
        }
    } catch (SQLException io) {
        throw new RuntimeException(io);
    }
}

// Bounded retry then dead-letter, with guaranteed forward progress.
void runLoop(KafkaConsumer<String, byte[]> consumer,
             KafkaProducer<String, byte[]> dltProducer) {
    consumer.subscribe(List.of("orders"));
    while (running) {
        var records = consumer.poll(Duration.ofMillis(200));
        for (var r : records) {
            handleWithRetry(r, dltProducer);
        }
        if (!records.isEmpty()) consumer.commitSync();
    }
}

void handleWithRetry(ConsumerRecord<String, byte[]> r,
                     KafkaProducer<String, byte[]> dlt) {
    int maxAttempts = 3;
    for (int attempt = 1; ; attempt++) {
        try {
            process(r.value());        // throws PermanentException or transient
            return;                    // success -> offset advances on commit
        } catch (PermanentException pe) {
            deadLetter(r, dlt, pe);    // never retry a poison pill
            return;
        } catch (TransientException te) {
            if (attempt >= maxAttempts) {
                deadLetter(r, dlt, te); // give up after bounded retries
                return;
            }
            sleepBackoff(attempt);     // e.g. 200ms * 2^attempt, capped
        }
    }
}

void deadLetter(ConsumerRecord<String, byte[]> r,
                KafkaProducer<String, byte[]> dlt, Exception cause) {
    var rec = new ProducerRecord<>("orders.DLT", r.key(), r.value());
    rec.headers()
       .add("x-error", cause.toString().getBytes(UTF_8))
       .add("x-source", (r.topic()+"-"+r.partition()+"-"+r.offset()).getBytes(UTF_8))
       .add("x-ts", Long.toString(System.currentTimeMillis()).getBytes(UTF_8));
    dlt.send(rec);
    dlt.flush();   // ensure DLT write is durable BEFORE we commit past it
}
